SELECT inspection_date, outcome, inspector_id, issues_identified, followup_required, followup_date
FROM compliance
ORDER BY inspection_date DESC;

SELECT COUNT(*) AS number_of_beekeepers
FROM beekeepers
WHERE registered_hives > 1;

SELECT city, COUNT(*) as count
FROM ordinances
GROUP BY city;

SELECT AVG(duration_seconds) AS average_duration_seconds
FROM access_logs
WHERE access_date >= DATE('now', '-7 days');

SELECT name, contact_info
FROM beekeepers
WHERE city_id = 1;

SELECT contact_info
FROM beekeepers
WHERE beekeeper_id = 0;
